using System.ComponentModel;
using System.Text.Json;

namespace ResearchAgent;

public sealed class ResearchTools(HttpClient httpClient)
{
    private readonly List<string> _notes = [];

    [Description("Search the web for information on a query. Returns relevant results.")]
    public async Task<string> SearchWeb(
        [Description("The search query")] string query)
    {
        try
        {
            var encoded = Uri.EscapeDataString(query);
            var url = $"https://api.duckduckgo.com/?q={encoded}&format=json&no_html=1&skip_disambig=1";
            var json = await httpClient.GetStringAsync(url);

            using var doc = JsonDocument.Parse(json);
            var root = doc.RootElement;

            var results = new List<string>();

            var abstractText = root.GetProperty("AbstractText").GetString();
            if (!string.IsNullOrWhiteSpace(abstractText))
            {
                var source = root.GetProperty("AbstractSource").GetString();
                results.Add($"[{source}] {abstractText}");
            }

            if (root.TryGetProperty("RelatedTopics", out var topics))
            {
                foreach (var topic in topics.EnumerateArray().Take(5))
                {
                    var text = topic.TryGetProperty("Text", out var t) ? t.GetString() : null;
                    if (!string.IsNullOrWhiteSpace(text))
                    {
                        results.Add($"- {text}");
                    }
                }
            }

            return results.Count > 0
                ? string.Join("\n", results)
                : $"No detailed results found for '{query}'. Try a different search query.";
        }
        catch (Exception ex)
        {
            return $"Search failed: {ex.Message}. Try a different query.";
        }
    }

    [Description("Save a research note with a title and content for later reference.")]
    public string SaveNote(
        [Description("Title of the note")] string title,
        [Description("Content/findings to save")] string content)
    {
        _notes.Add($"## {title}\n{content}");
        return $"Note saved: '{title}' ({_notes.Count} total notes)";
    }

    [Description("Retrieve all saved research notes to compile a final summary.")]
    public string GetNotes()
    {
        return _notes.Count == 0
            ? "No notes saved yet."
            : string.Join("\n\n", _notes);
    }

    public void ClearNotes() => _notes.Clear();
}

