using System.ClientModel;
using Microsoft.Agents.AI;
using Microsoft.Extensions.AI;
using OpenAI;
using ResearchAgent;

var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the OPENAI_API_KEY environment variable before running.");

var modelId = Environment.GetEnvironmentVariable("OPENAI_MODEL") ?? "gpt-4o-mini-2024-07-18";

IChatClient chatClient = new OpenAIClient(new ApiKeyCredential(apiKey))
    .GetChatClient(modelId)
    .AsIChatClient();

var researchTools = new ResearchTools(new HttpClient());
IList<AITool> tools =
[
    AIFunctionFactory.Create(researchTools.SearchWeb),
    AIFunctionFactory.Create(researchTools.SaveNote),
    AIFunctionFactory.Create(researchTools.GetNotes),
];

var agent = new ChatClientAgent(
    chatClient,
    instructions: """
        You are a research agent. When given a topic:
        1. Search the web multiple times with different queries to gather information.
        2. Save important findings as notes using the SaveNote tool.
        3. After gathering enough information, retrieve all notes and produce a
           concise, well-structured summary with key findings.
        Always cite what you found. Be thorough but concise.
        """,
    name: "ResearchAgent",
    description: "An agent that researches topics using web search and note-taking.",
    tools: tools);

Console.WriteLine("Research Agent Ready! Enter a topic to research (or 'quit' to exit):");

while (true)
{
    Console.Write("\n> ");
    var topic = Console.ReadLine()?.Trim();
    if (string.IsNullOrEmpty(topic) || topic.Equals("quit", StringComparison.OrdinalIgnoreCase))
        break;

    Console.WriteLine($"\nResearching: {topic}\n");

    var session = await agent.CreateSessionAsync(
        conversationId: Guid.NewGuid().ToString());

    var runOptions = new ChatClientAgentRunOptions
    {
        ChatOptions = new ChatOptions
        {
            Temperature = 0f,
            MaxOutputTokens = 2048,
        },
    };

    try
    {
        var response = await agent.RunAsync(
            $"Research the following topic and provide a summary: {topic}",
            session,
            runOptions);

        Console.WriteLine(response.Text);
    }
    catch (Exception ex)
    {
        Console.WriteLine($"Error: {ex.Message}");
    }

    researchTools.ClearNotes();
}

